content.content:
1	@tailwind base;
2	@tailwind components;
3	@tailwind utilities;
4	
5	@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');
6	
7	@layer base {
8	    html { @apply antialiased; }
9	    body { @apply bg-gray-50 text-gray-900 font-sans; }
10	}
11	
12	@layer components {
13	    /* Buttons */
14	    .btn           { @apply inline-flex items-center justify-center gap-2 rounded-lg px-4 py-2 text-sm font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed; }
15	    .btn-primary   { @apply btn bg-blue-600 text-white hover:bg-blue-700 focus:ring-blue-500; }
16	    .btn-secondary { @apply btn bg-emerald-600 text-white hover:bg-emerald-700 focus:ring-emerald-500; }
17	    .btn-danger    { @apply btn bg-red-600 text-white hover:bg-red-700 focus:ring-red-500; }
18	    .btn-ghost     { @apply btn bg-transparent text-gray-700 hover:bg-gray-100 focus:ring-gray-300; }
19	    .btn-outline   { @apply btn border border-gray-300 bg-white text-gray-700 hover:bg-gray-50 focus:ring-blue-500; }
20	    .btn-sm        { @apply px-3 py-1.5 text-xs; }
21	    .btn-lg        { @apply px-6 py-3 text-base; }
22	
23	    /* Form inputs */
24	    .form-input    { @apply block w-full rounded-lg border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm; }
25	    .form-select   { @apply block w-full rounded-lg border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm; }
26	    .form-label    { @apply block text-sm font-medium text-gray-700 mb-1; }
27	    .form-error    { @apply mt-1 text-xs text-red-600; }
28	    .form-hint     { @apply mt-1 text-xs text-gray-500; }
29	
30	    /* Cards */
31	    .card          { @apply bg-white rounded-xl shadow-sm border border-gray-200; }
32	    .card-header   { @apply px-6 py-4 border-b border-gray-200; }
33	    .card-body     { @apply p-6; }
34	    .card-footer   { @apply px-6 py-4 border-t border-gray-200 bg-gray-50 rounded-b-xl; }
35	
36	    /* Table */
37	    .table-wrapper  { @apply overflow-x-auto rounded-xl border border-gray-200; }
38	    .data-table     { @apply min-w-full divide-y divide-gray-200; }
39	    .data-table thead { @apply bg-gray-50; }
40	    .data-table th  { @apply px-4 py-3 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider; }
41	    .data-table td  { @apply px-4 py-3 text-sm text-gray-700; }
42	    .data-table tbody tr { @apply hover:bg-gray-50 transition-colors; }
43	    .data-table tbody tr:not(:last-child) { @apply border-b border-gray-100; }
44	
45	    /* Badges */
46	    .badge          { @apply inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium; }
47	    .badge-green    { @apply badge bg-green-100 text-green-800; }
48	    .badge-red      { @apply badge bg-red-100 text-red-800; }
49	    .badge-yellow   { @apply badge bg-yellow-100 text-yellow-800; }
50	    .badge-blue     { @apply badge bg-blue-100 text-blue-800; }
51	    .badge-gray     { @apply badge bg-gray-100 text-gray-700; }
52	    .badge-purple   { @apply badge bg-purple-100 text-purple-800; }
53	    .badge-orange   { @apply badge bg-orange-100 text-orange-800; }
54	
55	    /* Sidebar nav */
56	    .nav-item       { @apply flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium text-gray-600 hover:bg-gray-100 hover:text-gray-900 transition-colors; }
57	    .nav-item.active { @apply bg-blue-50 text-blue-700; }
58	
59	    /* Risk severity */
60	    .risk-critical  { @apply badge bg-red-100 text-red-900; }
61	    .risk-high      { @apply badge bg-orange-100 text-orange-900; }
62	    .risk-medium    { @apply badge bg-yellow-100 text-yellow-900; }
63	    .risk-low       { @apply badge bg-green-100 text-green-900; }
64	
65	    /* Finding status */
66	    .status-met          { @apply badge bg-green-100 text-green-800; }
67	    .status-partially-met { @apply badge bg-yellow-100 text-yellow-800; }
68	    .status-not-met      { @apply badge bg-red-100 text-red-800; }
69	    .status-na           { @apply badge bg-gray-100 text-gray-600; }
70	}
